"use client";

import { Icon } from "@/components/shared/icon";
import { StatusBadge } from "@/components/shared/status-badge";
import type {
  WorkflowEdge,
  WorkflowNodeCard,
  WorkflowPortSide,
  WorkflowSnapshot,
  WorkflowTemplateScenario,
} from "@/lib/types";
import { cx } from "@/lib/utils";

type WorkflowCanvasProps = {
  template: WorkflowTemplateScenario;
  snapshot: WorkflowSnapshot;
  selectedNodeId: string;
  scale: number;
  onNodeSelect: (nodeId: string) => void;
  onZoomIn: () => void;
  onZoomOut: () => void;
  onZoomReset: () => void;
};

type Point = {
  x: number;
  y: number;
};

const nodeStateClasses: Record<WorkflowNodeCard["state"], string> = {
  idle: "border-white/8 bg-white/4",
  active: "border-cyan-400/18 bg-cyan-400/10",
  success: "border-emerald-400/20 bg-emerald-400/10",
  warning: "border-amber-400/20 bg-amber-400/10",
  error: "border-rose-400/20 bg-rose-400/10",
};

function getPortPosition(node: WorkflowNodeCard, side: WorkflowPortSide): Point {
  if (side === "left") {
    return { x: node.x, y: node.y + node.height / 2 };
  }

  if (side === "right") {
    return { x: node.x + node.width, y: node.y + node.height / 2 };
  }

  if (side === "top") {
    return { x: node.x + node.width / 2, y: node.y };
  }

  return { x: node.x + node.width / 2, y: node.y + node.height };
}

function getEdgePath(edge: WorkflowEdge, nodes: Record<string, WorkflowNodeCard>) {
  const sourceNode = nodes[edge.source];
  const targetNode = nodes[edge.target];

  if (!sourceNode || !targetNode) {
    return null;
  }

  const start = getPortPosition(sourceNode, edge.sourceSide);
  const end = getPortPosition(targetNode, edge.targetSide);
  const horizontalCurve = Math.max(Math.abs(end.x - start.x) * 0.38, 42);
  const verticalCurve = Math.max(Math.abs(end.y - start.y) * 0.32, 42);

  const cp1 =
    edge.sourceSide === "left"
      ? { x: start.x - horizontalCurve, y: start.y }
      : edge.sourceSide === "right"
        ? { x: start.x + horizontalCurve, y: start.y }
        : edge.sourceSide === "top"
          ? { x: start.x, y: start.y - verticalCurve }
          : { x: start.x, y: start.y + verticalCurve };

  const cp2 =
    edge.targetSide === "left"
      ? { x: end.x - horizontalCurve, y: end.y }
      : edge.targetSide === "right"
        ? { x: end.x + horizontalCurve, y: end.y }
        : edge.targetSide === "top"
          ? { x: end.x, y: end.y - verticalCurve }
          : { x: end.x, y: end.y + verticalCurve };

  return `M ${start.x} ${start.y} C ${cp1.x} ${cp1.y}, ${cp2.x} ${cp2.y}, ${end.x} ${end.y}`;
}

function getEdgeLabelPosition(edge: WorkflowEdge, nodes: Record<string, WorkflowNodeCard>) {
  const sourceNode = nodes[edge.source];
  const targetNode = nodes[edge.target];

  if (!sourceNode || !targetNode) {
    return null;
  }

  const start = getPortPosition(sourceNode, edge.sourceSide);
  const end = getPortPosition(targetNode, edge.targetSide);

  return {
    x: (start.x + end.x) / 2,
    y: (start.y + end.y) / 2,
  };
}

export function WorkflowCanvas({
  template,
  snapshot,
  selectedNodeId,
  scale,
  onNodeSelect,
  onZoomIn,
  onZoomOut,
  onZoomReset,
}: WorkflowCanvasProps) {
  const nodeMap = Object.fromEntries(template.nodes.map((node) => [node.id, node])) as Record<
    string,
    WorkflowNodeCard
  >;
  const canvasWidth = Math.max(...template.nodes.map((node) => node.x + node.width)) + 180;
  const canvasHeight = Math.max(...template.nodes.map((node) => node.y + node.height)) + 180;
  const scaledWidth = canvasWidth * scale;
  const scaledHeight = canvasHeight * scale;

  return (
    <div className="flex min-h-[820px] flex-col">
      <div
        className="flex flex-wrap items-center justify-between gap-3 border-b px-4 py-3"
        style={{ borderColor: "var(--border)" }}
      >
        <div>
          <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-tertiary">
            Workflow Canvas
          </p>
          <div className="mt-2 flex flex-wrap items-center gap-2">
            <StatusBadge status={snapshot.status} />
            <span className="chip rounded-full px-2.5 py-1 text-[10px] font-semibold uppercase tracking-[0.16em]">
              {template.nodeCount} nodes
            </span>
            <span className="chip rounded-full px-2.5 py-1 text-[10px] font-semibold uppercase tracking-[0.16em]">
              保存于 {snapshot.savedAt}
            </span>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <span className="chip rounded-full px-2.5 py-1 text-[10px] font-semibold uppercase tracking-[0.16em]">
            缩放 {Math.round(scale * 100)}%
          </span>
          <button type="button" onClick={onZoomOut} className="button-secondary rounded-xl px-3 py-2 text-sm font-semibold">
            -
          </button>
          <button type="button" onClick={onZoomReset} className="button-secondary rounded-xl px-3 py-2 text-xs font-semibold">
            重置
          </button>
          <button type="button" onClick={onZoomIn} className="button-secondary rounded-xl px-3 py-2 text-sm font-semibold">
            +
          </button>
        </div>
      </div>

      <div className="workflow-grid scrollbar-thin relative min-h-[744px] overflow-auto">
        <div className="relative" style={{ width: scaledWidth, height: scaledHeight }}>
          <div
            className="absolute left-0 top-0"
            style={{
              width: canvasWidth,
              height: canvasHeight,
              transform: `scale(${scale})`,
              transformOrigin: "top left",
            }}
          >
            <svg
              className="pointer-events-none absolute inset-0 h-full w-full"
              viewBox={`0 0 ${canvasWidth} ${canvasHeight}`}
              fill="none"
            >
              {template.edges.map((edge) => {
                const path = getEdgePath(edge, nodeMap);

                if (!path) {
                  return null;
                }

                return (
                  <path
                    key={edge.id}
                    d={path}
                    stroke={edge.style === "dashed" ? "var(--accent)" : "var(--foreground-soft)"}
                    strokeWidth={edge.style === "dashed" ? 2.2 : 2}
                    strokeDasharray={edge.style === "dashed" ? "8 8" : undefined}
                    opacity={edge.style === "dashed" ? 0.72 : 0.86}
                  />
                );
              })}
            </svg>

            {template.edges.map((edge) => {
              if (!edge.label) {
                return null;
              }

              const labelPosition = getEdgeLabelPosition(edge, nodeMap);

              if (!labelPosition) {
                return null;
              }

              return (
                <div
                  key={`${edge.id}-label`}
                  className="chip-accent absolute -translate-x-1/2 -translate-y-1/2 rounded-full px-2.5 py-1 text-[10px] font-semibold"
                  style={{ left: labelPosition.x, top: labelPosition.y }}
                >
                  {edge.label}
                </div>
              );
            })}

            {template.nodes.map((node) => {
              const selected = node.id === selectedNodeId;
              const isResource = node.kind === "resource";

              return (
                <button
                  key={node.id}
                  type="button"
                  onClick={() => onNodeSelect(node.id)}
                  className={cx(
                    "absolute border text-left transition duration-150",
                    nodeStateClasses[node.state],
                    isResource
                      ? "flex items-center justify-center rounded-full p-4"
                      : "flex flex-col justify-between rounded-[28px] px-4 py-3",
                    selected && "ring-2 ring-cyan-400/30 shadow-[0_18px_42px_rgba(15,118,110,0.14)]",
                  )}
                  style={{ left: node.x, top: node.y, width: node.width, height: node.height }}
                >
                  <span
                    className="absolute left-[-5px] top-1/2 h-2.5 w-2.5 -translate-y-1/2 rounded-full border"
                    style={{ borderColor: "var(--border-strong)", background: "var(--surface-strong)" }}
                  />
                  <span
                    className="absolute right-[-5px] top-1/2 h-2.5 w-2.5 -translate-y-1/2 rounded-full border"
                    style={{ borderColor: "var(--border-strong)", background: "var(--surface-strong)" }}
                  />
                  <span
                    className="absolute left-1/2 top-[-5px] h-2.5 w-2.5 -translate-x-1/2 rounded-full border"
                    style={{ borderColor: "var(--border-strong)", background: "var(--surface-strong)" }}
                  />
                  <span
                    className="absolute bottom-[-5px] left-1/2 h-2.5 w-2.5 -translate-x-1/2 rounded-full border"
                    style={{ borderColor: "var(--border-strong)", background: "var(--surface-strong)" }}
                  />

                  {isResource ? (
                    <div className="flex flex-col items-center justify-center text-center">
                      <div className="surface-card-strong flex h-12 w-12 items-center justify-center rounded-full">
                        <Icon name={node.icon} className="h-5 w-5 text-primary" />
                      </div>
                      <p className="mt-3 text-sm font-semibold text-primary">{node.title}</p>
                      <p className="mt-1 text-xs leading-5 text-secondary">{node.subtitle}</p>
                    </div>
                  ) : (
                    <>
                      <div>
                        <div className="flex items-start justify-between gap-3">
                          <div className="flex items-center gap-3">
                            <div className="surface-card-strong flex h-11 w-11 items-center justify-center rounded-2xl">
                              <Icon name={node.icon} className="h-5 w-5 text-primary" />
                            </div>
                            <div>
                              <p className="text-sm font-semibold text-primary">{node.title}</p>
                              <p className="mt-1 text-xs leading-5 text-secondary">{node.subtitle}</p>
                            </div>
                          </div>

                          {node.badges?.length ? (
                            <span className="chip rounded-full px-2 py-1 text-[10px] font-semibold uppercase tracking-[0.16em]">
                              {node.badges[0]}
                            </span>
                          ) : null}
                        </div>
                      </div>

                      <div className="mt-4 grid gap-2">
                        {node.fields.slice(0, 2).map((field) => (
                          <div key={field.label} className="flex items-center justify-between gap-4 text-xs">
                            <span className="text-tertiary">{field.label}</span>
                            <span className="text-right font-medium text-primary">{field.value}</span>
                          </div>
                        ))}
                      </div>
                    </>
                  )}
                </button>
              );
            })}
          </div>
        </div>

        <div className="pointer-events-none absolute inset-x-0 top-0 flex justify-center p-4">
          <div className="surface-card-strong inline-flex items-center gap-3 rounded-full px-4 py-2 text-xs text-secondary">
            <span className="font-semibold text-primary">{snapshot.title}</span>
            <span className="h-1 w-1 rounded-full bg-[var(--border-strong)]" />
            {snapshot.summary}
          </div>
        </div>

        <div className="absolute bottom-4 left-4 flex items-center gap-2">
          <button type="button" onClick={onZoomReset} className="button-secondary rounded-2xl px-3 py-2 text-xs font-semibold">
            适应画布
          </button>
          <button type="button" className="button-primary rounded-2xl px-3 py-2 text-xs font-semibold">
            {snapshot.actionLabel}
          </button>
        </div>
      </div>
    </div>
  );
}
